import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirUtil, hirAppActions as appActions, MyDialog, MyTable} from '../../../utils';
import { Fab, TableCell, Button } from '@material-ui/core';
import { Add, Delete } from '@material-ui/icons';
import { HIRNewAppointment } from '../../../HIRAppointments/HIRNewAppointment';
import { hirPatientStrings } from '../../config';
import { hirPatientActions } from '../../actions';
import { hirSettingStrings, hirSettingActions } from '../../../HIRSettings/config';

const style = theme => ({
    root: {
    },
    fab : {},
    icon :{},
    table : {
        backgroundColor : "transparent",
    },
    cell : {
        padding : 5,
        fontSize : 11
    },
    rowHighlight : {
        backgroundColor : hirUtil.getTheme().primary,
        color : hirUtil.getTheme().white
    }
})
class _HIRAppointments extends Component {
    state = {
        newAptDialog : false,
    }
    componentDidMount() {
        const {
            dispatch, 
            patientId,
            [hirSettingStrings.settings] : settings
        } = this.props;
        hirPatientActions.getPatientAppointments(patientId)(dispatch);
        if(!settings) hirSettingActions.getSettings()(dispatch);
    }
    
    createAppointment(data, context){
        const {patientId, dispatch} = this.props;
        hirPatientActions.bookPatientAppointment(
            {patientId, ...data}, (done) => {
                context.setState({loading : false});
                if(done) this.setState({newAptDialog : false});
            }
        )(dispatch);
    }
    deleteAppointment = (appointId) => () => {
        const {dispatch, patientId} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirPatientActions.deleteAppointment(patientId, appointId)(dispatch);
    }
    appointmentDeleteWarning = appointment => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to delete this appointment?",
            [<Button key={"deleteAppoint"+appointment._id} onClick={this.deleteAppointment(appointment._id)}>Delete</Button>]
        )(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes, [hirSettingStrings.settings] : settings} =this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                {!row.visit && 
                    <Delete fontSize color="secondary" fontSize="small"
                        onClick={this.appointmentDeleteWarning(row)}/>}
            </TableCell>
            case "date" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "unit" : 
                let unit = row[cellMap];
                if(settings){
                    const units = settings.find(item=>item.name === "units");
                    const unitValue = units.values.find(item=>item.name === row[cellMap]);
                    unit = unitValue && unitValue.value
                }
                return <TableCell className={classes.cell}>
                    {unit}
                </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).substr(0, 6)}...
            </TableCell> 
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [hirPatientStrings.patientAppointments] : patientAppointments,
            patientId, patient
        } = this.props;
        const {newAptDialog} = this.state;
        let appointments;
        if(patientAppointments)
            appointments = patientAppointments[patientId];
        return (
            <div className={classes.root}>
                <MyTable
                    classes={{root : classes.table}}
                    elevation={0}
                    title="Appointments"
                    header={["ID", "Unit", "Date", "Action"]}
                    dataMap={["_id", "unit", "date", "action"]}
                    data={appointments || []}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowStyleCondition={row=>row.visit && classes.rowHighlight}
                    />
                <Fab className={classes.fab} 
                    size="small"
                    onClick={()=>this.setState({newAptDialog : true})}>
                    <Add className={classes.icon}/>
                </Fab>
                <MyDialog 
                    open={newAptDialog}
                    close={()=>this.setState({newAptDialog : false})}>
                        <HIRNewAppointment
                            patient={this.props.patient}
                            createAppointment={this.createAppointment.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_HIRAppointments.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    patientId : PropTypes.number,
};
const mapStateToProps = ({hirPatientReducer, hirSettingReducer}) => ({
    [hirPatientStrings.patientAppointments] : hirPatientReducer[hirPatientStrings.patientAppointments],
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings]
})


export const HIRAppointments = connect(mapStateToProps)(withStyles(style)(_HIRAppointments));
export {HIRAppointments as default}