import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirPatientActions } from '../../../actions';
import { FormLabel, Typography } from '@material-ui/core';
import { hirUtil } from '../../../../utils';


const style = theme => ({
    root: {
        backgroundColor : hirUtil.getTheme().background,
        borderRadius : 20,
        minHeight : 200,
        padding : 10,
        margin : 5,
    },
    headerContainer : {
        marginBottom : 20
    },
    header : {
        color : hirUtil.getTheme().primary1,
    },
    name : {

    }
})
class _HIRPatientFamilyMembers extends Component {
    state = {
        family : null
    }
    componentDidMount() {
        const {familyId, patientId, dispatch} = this.props;
        hirPatientActions.getFamily(familyId, (done, result)=>{
            if(done){
                this.setState({family : result});
            }
        })(dispatch);
    }
    
    render() {
        const {classes, patientId} = this.props;
        const {family} = this.state;
        console.log(this.state);
        let members;
        if(family){
            const {familyMembers} = family;
            if(familyMembers){
                const index = familyMembers.findIndex(item=>item._id === parseInt(patientId));
                // if(index) familyMembers.splice(index,1);
                members = familyMembers
            }
        }
        return (
            <div className={classes.root}>
                <div className={classes.headerContainer}>
                    <FormLabel className={classes.header}>Family</FormLabel>
                    <Typography>{family ? family.name : null}</Typography>
                </div>
                <div>
                    <FormLabel className={classes.member}>Members</FormLabel>
                    {members && members.map((item, index)=>{
                        const {lastName, firstName} = item.myProfile;
                        return <Typography key={index} className={classes.name}>
                            {lastName && lastName}, {firstName && firstName}
                        </Typography>
                    })}
                </div>
            </div>
        );
    }
}


_HIRPatientFamilyMembers.propTypes = {
    classes : PropTypes.object.isRequired,
    familyId : PropTypes.number,
    patientId : PropTypes.number,
};



export const HIRPatientFamilyMembers = connect()(withStyles(style)(_HIRPatientFamilyMembers));
export {HIRPatientFamilyMembers as default}