import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirPatientActions } from '../../../actions';
import { hirUtil, hirMonthLabel as monthLabels, MyChart } from '../../../../utils';


const style = theme => ({
    root: {
    }
})
class _HIRPatientYearlyPayments extends Component {
    constructor(props) {
        super(props);
        this.state={
            payments : null, 
            year : null
        }
        props.getContext(this);
    }
    static async getData(year, patientId, dispatch, callback){
        let value;
        try{
            value = await hirPatientActions.getPatientYearlyPayments(patientId, year)(dispatch);
            if(callback) callback(null, value);
        }catch(message){
            value = null;
            if(callback) callback(message);
        }
        return value;
    }
    deriveMonthlyData(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    }
    render() {
        const {classes, data, year} = this.props;
        console.log(this.props);
        return (
            <MyChart
                canvasId="paymentYearMonth"
                title={"Monthly Revenue " + year +" (line)"}
                labels={monthLabels}
                datasets={[{
                    label: 'Total amount (N)',
                    data : this.deriveMonthlyData(data, "total"),                                
                    backgroundColor : hirUtil.getTheme().primaryTrans,
                    borderColor : hirUtil.getTheme().primary,
                }]}
            />
        );
    }
}


_HIRPatientYearlyPayments.propTypes = {
    classes : PropTypes.object.isRequired,
    patientId : PropTypes.number,
    year : PropTypes.number,
};
const mapStateToProps = state => ({
    state
})


export const HIRPatientYearlyPayments = connect(mapStateToProps)(withStyles(style)(_HIRPatientYearlyPayments));
export {HIRPatientYearlyPayments as default}